// Version and release history — loaded from releases.json (generated by npm run releases)
let APP_VERSION = '...';
let RELEASES = [];

// Document type definitions with Hebrew labels
const DOCUMENT_TYPES = {
  ID_CARD: { label: 'תעודת זהות', icon: '🪪', color: '#3B82F6' },
  ID_CARD_APPENDIX: { label: 'נספח לתעודת זהות', icon: '📑', color: '#60A5FA' },
  PASSPORT: { label: 'דרכון', icon: '📘', color: '#8B5CF6' },
  DRIVERS_LICENSE: { label: 'רישיון נהיגה', icon: '🚗', color: '#EC4899' },
  VEHICLE_LICENSE: { label: 'רישיון רכב', icon: '🚙', color: '#F472B6' },
  BANK_STATEMENT: { label: 'דף חשבון בנק', icon: '🏦', color: '#10B981' },
  SALARY_SLIP: { label: 'תלוש שכר', icon: '💰', color: '#F59E0B' },
  TAX_DOCUMENT: { label: 'מסמך מס', icon: '📋', color: '#EF4444' },
  UTILITY_BILL: { label: 'חשבון שירות', icon: '💡', color: '#06B6D4' },
  PROOF_OF_ADDRESS: { label: 'אישור כתובת', icon: '🏠', color: '#14B8A6' },
  EMPLOYMENT_LETTER: { label: 'אישור העסקה', icon: '💼', color: '#6366F1' },
  OTHER: { label: 'אחר', icon: '📄', color: '#6B7280' },
};

// State
let uploadedPages = [];
let classifications = [];
let groupedDocuments = [];
let extractedDataMap = {};
const debugLog = [];

// DOM elements
const dropZone = document.getElementById('dropZone');
const fileInput = document.getElementById('fileInput');
const fileInfo = document.getElementById('fileInfo');
const fileName = document.getElementById('fileName');
const fileSize = document.getElementById('fileSize');
const actions = document.getElementById('actions');
const classifyBtn = document.getElementById('classifyBtn');
const extractBtn = document.getElementById('extractBtn');
const saveBtn = document.getElementById('saveBtn');
const progress = document.getElementById('progress');
const progressText = document.getElementById('progressText');
const statusMessage = document.getElementById('statusMessage');
const pagesSection = document.getElementById('pagesSection');
const pagesGrid = document.getElementById('pagesGrid');
const documentsSection = document.getElementById('documentsSection');
const documentsList = document.getElementById('documentsList');
const extractionSection = document.getElementById('extractionSection');
const extractionResults = document.getElementById('extractionResults');
const debugContent = document.getElementById('debugContent');
const copyDebugBtn = document.getElementById('copyDebugBtn');
const legendGrid = document.getElementById('legendGrid');
const summarySection = document.getElementById('summarySection');
const summarizeBtn = document.getElementById('summarizeBtn');
const summaryContent = document.getElementById('summaryContent');

// Initialize legend
function initLegend() {
  legendGrid.innerHTML = Object.entries(DOCUMENT_TYPES)
    .map(
      ([key, { label, icon, color }]) => `
    <div class="legend-item">
      <span class="legend-dot" style="background: ${color}"></span>
      <span>${icon}</span>
      <span class="legend-label">${label} (${key})</span>
    </div>
  `
    )
    .join('');
}

// Format file size
function formatSize(bytes) {
  if (bytes < 1024) return bytes + ' B';
  if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
  return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
}

// Show/hide progress
function showProgress(text) {
  progress.classList.add('visible');
  progressText.textContent = text;
}

function hideProgress() {
  progress.classList.remove('visible');
}

// Show status message
function showStatus(message, type = 'success') {
  statusMessage.textContent = message;
  statusMessage.className = `status-message visible ${type}`;
  setTimeout(() => {
    statusMessage.classList.remove('visible');
  }, 5000);
}

// Add debug entry
function addDebug(label, data) {
  const entry = {
    label,
    timestamp: new Date().toISOString(),
    data,
  };
  debugLog.push(entry);
  renderDebug();
}

function renderDebug() {
  debugContent.innerHTML = debugLog
    .map(
      (entry) => `
    <div class="debug-entry">
      <div class="debug-label">${entry.label}</div>
      <div class="debug-time">${entry.timestamp}</div>
      <pre>${typeof entry.data === 'string' ? entry.data : JSON.stringify(entry.data, null, 2)}</pre>
    </div>
  `
    )
    .join('');
}

// Copy debug info to clipboard
copyDebugBtn.addEventListener('click', async () => {
  const text = debugLog
    .map((entry) => {
      const data = typeof entry.data === 'string' ? entry.data : JSON.stringify(entry.data, null, 2);
      return `=== ${entry.label} ===\n${entry.timestamp}\n${data}`;
    })
    .join('\n\n');

  try {
    await navigator.clipboard.writeText(text);
    copyDebugBtn.textContent = '✅ Copied!';
    copyDebugBtn.classList.add('copied');
    setTimeout(() => {
      copyDebugBtn.textContent = '📋 Copy All';
      copyDebugBtn.classList.remove('copied');
    }, 2000);
  } catch {
    // Fallback for non-HTTPS
    const textarea = document.createElement('textarea');
    textarea.value = text;
    document.body.appendChild(textarea);
    textarea.select();
    document.execCommand('copy');
    document.body.removeChild(textarea);
    copyDebugBtn.textContent = '✅ Copied!';
    copyDebugBtn.classList.add('copied');
    setTimeout(() => {
      copyDebugBtn.textContent = '📋 Copy All';
      copyDebugBtn.classList.remove('copied');
    }, 2000);
  }
});

// Drag and drop handling
dropZone.addEventListener('dragover', (e) => {
  e.preventDefault();
  dropZone.classList.add('dragover');
});

dropZone.addEventListener('dragleave', () => {
  dropZone.classList.remove('dragover');
});

dropZone.addEventListener('drop', (e) => {
  e.preventDefault();
  dropZone.classList.remove('dragover');
  const files = Array.from(e.dataTransfer.files);
  if (files.length > 0) handleFiles(files);
});

dropZone.addEventListener('click', () => {
  fileInput.click();
});

fileInput.addEventListener('change', (e) => {
  const files = Array.from(e.target.files);
  if (files.length > 0) handleFiles(files);
});

// Handle multiple file upload
async function handleFiles(files) {
  const totalSize = files.reduce((sum, f) => sum + f.size, 0);
  const names = files.map((f) => f.name).join(', ');

  fileName.textContent = files.length === 1 ? files[0].name : `${files.length} files: ${names}`;
  fileSize.textContent = formatSize(totalSize);
  fileInfo.classList.add('visible');

  addDebug('Files Selected', {
    count: files.length,
    files: files.map((f) => ({ name: f.name, size: formatSize(f.size), type: f.type })),
  });

  showProgress(`Uploading ${files.length} file(s) and converting pages...`);

  const formData = new FormData();
  for (const file of files) {
    formData.append('documents', file);
  }

  try {
    const startTime = Date.now();
    const response = await fetch('/api/upload', {
      method: 'POST',
      body: formData,
    });

    if (!response.ok) {
      const error = await response.json();
      throw new Error(error.details || error.error || 'Upload failed');
    }

    const data = await response.json();
    const uploadTime = Date.now() - startTime;

    uploadedPages = data.pages;

    addDebug('Upload Complete', {
      pageCount: data.pageCount,
      fileCount: data.fileCount,
      files: data.files,
      serverProcessingTime: data.processingTime + 'ms',
      totalTime: uploadTime + 'ms',
    });

    renderPages();

    actions.style.display = 'flex';
    classifyBtn.disabled = false;

    hideProgress();
    showStatus(`Successfully processed ${data.fileCount} file(s) into ${data.pageCount} page(s)`);
  } catch (error) {
    hideProgress();
    showStatus(error.message, 'error');
    addDebug('Upload Error', { error: error.message });
  }
}

// Render page thumbnails (before classification)
function renderPages() {
  pagesSection.classList.add('visible');
  pagesGrid.innerHTML = uploadedPages
    .map(
      (page) => `
    <div class="page-card" id="page-${page.pageNumber}">
      <img src="data:${page.mediaType || 'image/png'};base64,${page.base64}" alt="Page ${page.pageNumber}">
      <div class="page-info">
        <div class="page-number">Page ${page.pageNumber}${page.sourceFile ? ' — ' + page.sourceFile : ''}</div>
      </div>
    </div>
  `
    )
    .join('');
}

// Render page thumbnails with classification results
function renderClassifiedPages() {
  pagesGrid.innerHTML = uploadedPages
    .map((page) => {
      const classification = classifications.find((c) => c.page === page.pageNumber);
      if (!classification) return '';

      const docType = DOCUMENT_TYPES[classification.type] || DOCUMENT_TYPES.OTHER;

      return `
      <div class="page-card" id="page-${page.pageNumber}">
        ${classification.isFirstPage ? '<div class="new-doc-badge">NEW DOC</div>' : ''}
        <img src="data:${page.mediaType || 'image/png'};base64,${page.base64}" alt="Page ${page.pageNumber}">
        <div class="page-info">
          <div class="page-number">Page ${page.pageNumber}${page.sourceFile ? ' — ' + page.sourceFile : ''}</div>
          <span class="badge badge-${classification.type}">
            ${docType.icon} ${classification.type}
          </span>
          <div class="confidence">
            Confidence: ${classification.confidence} | ${docType.label}
          </div>
        </div>
      </div>
    `;
    })
    .join('');
}

// Classify documents
classifyBtn.addEventListener('click', async () => {
  classifyBtn.disabled = true;
  showProgress('Classifying documents with Claude AI...');

  addDebug('Classification Started', {
    pageCount: uploadedPages.length,
    timestamp: new Date().toISOString(),
  });

  try {
    const startTime = Date.now();
    const response = await fetch('/api/classify', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        pages: uploadedPages.map((p) => ({ base64: p.base64, mediaType: p.mediaType })),
      }),
    });

    if (!response.ok) {
      const error = await response.json();
      throw new Error(error.details || error.error || 'Classification failed');
    }

    const data = await response.json();
    const totalTime = Date.now() - startTime;

    classifications = data.classifications;

    addDebug('Classification Complete', {
      model: data.model,
      usage: data.usage,
      serverProcessingTime: data.processingTime + 'ms',
      totalTime: totalTime + 'ms',
      classifications: data.classifications,
    });

    addDebug('Raw API Response', data.rawResponse);

    renderClassifiedPages();

    groupedDocuments = groupIntoDocuments(classifications);

    addDebug('Document Grouping', {
      documentCount: groupedDocuments.length,
      documents: groupedDocuments.map((doc) => ({
        type: doc.type,
        pageCount: doc.pages.length,
        pages: doc.pages.map((p) => p.page),
      })),
    });

    renderDocuments();

    hideProgress();
    classifyBtn.disabled = false;
    extractBtn.disabled = false;
    saveBtn.disabled = false;
    showStatus(`Classified ${classifications.length} pages into ${groupedDocuments.length} documents`);
  } catch (error) {
    hideProgress();
    classifyBtn.disabled = false;
    showStatus(error.message, 'error');
    addDebug('Classification Error', { error: error.message });
  }
});

// Group pages into documents
function groupIntoDocuments(classificationList) {
  const documents = [];
  let currentDoc = null;

  for (const page of classificationList) {
    if (page.isFirstPage) {
      if (currentDoc) documents.push(currentDoc);
      currentDoc = {
        type: page.type,
        pages: [page],
        startPage: page.page,
      };
    } else if (currentDoc) {
      currentDoc.pages.push(page);
    } else {
      currentDoc = {
        type: page.type,
        pages: [page],
        startPage: page.page,
      };
    }
  }
  if (currentDoc) documents.push(currentDoc);

  return documents;
}

// Render grouped documents
function renderDocuments() {
  documentsSection.classList.add('visible');
  documentsList.innerHTML = groupedDocuments
    .map((doc, index) => {
      const docType = DOCUMENT_TYPES[doc.type] || DOCUMENT_TYPES.OTHER;
      const pageRange = doc.pages.map((p) => p.page).join(', ');
      const borderColor = docType.color;

      return `
      <div class="document-group" style="border-left-color: ${borderColor}">
        <div class="doc-header">
          <span class="doc-icon">${docType.icon}</span>
          <div>
            <div class="doc-type">${doc.type}</div>
            <div class="doc-label">${docType.label}</div>
          </div>
        </div>
        <div class="doc-pages">
          Document ${index + 1} — Pages: ${pageRange} (${doc.pages.length} page${doc.pages.length > 1 ? 's' : ''})
        </div>
      </div>
    `;
    })
    .join('');
}

// Extract data from all grouped documents
extractBtn.addEventListener('click', async () => {
  extractBtn.disabled = true;
  extractedDataMap = {};
  extractionSection.classList.add('visible');
  extractionResults.innerHTML = '';

  const totalDocs = groupedDocuments.length;
  let completed = 0;

  addDebug('Extraction Started', {
    documentCount: totalDocs,
    timestamp: new Date().toISOString(),
  });

  showProgress(`Extracting data from document 1 of ${totalDocs}...`);

  for (let i = 0; i < groupedDocuments.length; i++) {
    const doc = groupedDocuments[i];
    const docType = DOCUMENT_TYPES[doc.type] || DOCUMENT_TYPES.OTHER;

    progressText.textContent = `Extracting data from document ${i + 1} of ${totalDocs} (${docType.label})...`;

    try {
      const pageImages = doc.pages.map((p) => {
        const uploaded = uploadedPages.find((up) => up.pageNumber === p.page);
        return { base64: uploaded.base64, mediaType: uploaded.mediaType };
      });

      const startTime = Date.now();
      const response = await fetch('/api/extract', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          documentType: doc.type,
          pages: pageImages,
        }),
      });

      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.details || error.error || 'Extraction failed');
      }

      const data = await response.json();
      const totalTime = Date.now() - startTime;

      extractedDataMap[i] = data.extractedData;

      addDebug(`Extraction: ${doc.type} (Doc ${i + 1})`, {
        model: data.model,
        usage: data.usage,
        processingTime: data.processingTime + 'ms',
        totalTime: totalTime + 'ms',
        extractedData: data.extractedData,
      });

      completed++;
    } catch (error) {
      extractedDataMap[i] = { error: error.message };
      addDebug(`Extraction Error: ${doc.type} (Doc ${i + 1})`, { error: error.message });
      completed++;
    }
  }

  renderExtractionResults();
  hideProgress();
  extractBtn.disabled = false;
  summarizeBtn.disabled = false;
  summarySection.classList.add('visible');
  showStatus(`Extracted data from ${completed} of ${totalDocs} documents`);
});

// Render extraction results
function renderExtractionResults() {
  extractionResults.innerHTML = groupedDocuments
    .map((doc, index) => {
      const docType = DOCUMENT_TYPES[doc.type] || DOCUMENT_TYPES.OTHER;
      const data = extractedDataMap[index];
      const borderColor = docType.color;

      if (!data) {
        return `
        <div class="extraction-card" style="border-left-color: ${borderColor}">
          <div class="extraction-header">
            <span>${docType.icon}</span>
            <strong>${doc.type}</strong> — ${docType.label}
          </div>
          <div class="extraction-body">
            <span style="color: var(--text-muted);">Pending...</span>
          </div>
        </div>`;
      }

      if (data.error) {
        return `
        <div class="extraction-card" style="border-left-color: var(--error)">
          <div class="extraction-header">
            <span>${docType.icon}</span>
            <strong>${doc.type}</strong> — ${docType.label}
          </div>
          <div class="extraction-body">
            <span style="color: var(--error);">Error: ${data.error}</span>
          </div>
        </div>`;
      }

      const fieldsHtml = Object.entries(data)
        .map(([key, value]) => {
          const displayValue =
            value === null
              ? '<span style="color: var(--text-muted)">—</span>'
              : typeof value === 'object'
                ? `<pre style="margin:0;font-size:12px;">${JSON.stringify(value, null, 2)}</pre>`
                : `<span>${value}</span>`;
          return `
          <div class="extraction-field">
            <div class="field-key">${key}</div>
            <div class="field-value">${displayValue}</div>
          </div>`;
        })
        .join('');

      return `
      <div class="extraction-card" style="border-left-color: ${borderColor}">
        <div class="extraction-header">
          <span>${docType.icon}</span>
          <strong>${doc.type}</strong> — ${docType.label}
          <span style="color: var(--text-muted); font-size: 12px; margin-left: auto;">
            Pages: ${doc.pages.map((p) => p.page).join(', ')}
          </span>
        </div>
        <div class="extraction-body">
          ${fieldsHtml}
        </div>
      </div>`;
    })
    .join('');
}

// Simple markdown to HTML converter
function markdownToHtml(md) {
  return md
    .replace(/^## (.+)$/gm, '<h2>$1</h2>')
    .replace(/^- \*\*(.+?)\*\*:?\s*/gm, '<li><strong>$1</strong> ')
    .replace(/^- (.+)$/gm, '<li>$1</li>')
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/(<li>.*<\/li>\n?)+/g, (m) => `<ul>${m}</ul>`)
    .replace(/\n{2,}/g, '\n')
    .split('\n')
    .map((line) => {
      if (line.startsWith('<h2>') || line.startsWith('<ul>') || line.startsWith('<li>')) return line;
      if (line.trim() === '') return '';
      return `<p>${line}</p>`;
    })
    .join('\n');
}

// Generate AI summary
summarizeBtn.addEventListener('click', async () => {
  summarizeBtn.disabled = true;
  showProgress('Generating AI analysis summary...');

  addDebug('Summary Started', { timestamp: new Date().toISOString() });

  try {
    const startTime = Date.now();
    const response = await fetch('/api/summarize', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        documents: groupedDocuments.map((doc) => ({
          type: doc.type,
          pages: doc.pages,
        })),
        extractedData: extractedDataMap,
      }),
    });

    if (!response.ok) {
      const error = await response.json();
      throw new Error(error.details || error.error || 'Summary failed');
    }

    const data = await response.json();
    const totalTime = Date.now() - startTime;

    summaryContent.innerHTML = markdownToHtml(data.summary);
    summaryContent.classList.add('visible');

    addDebug('Summary Complete', {
      model: data.model,
      usage: data.usage,
      processingTime: data.processingTime + 'ms',
      totalTime: totalTime + 'ms',
    });

    addDebug('Raw Summary', data.summary);

    hideProgress();
    summarizeBtn.disabled = false;
    showStatus('AI summary generated successfully');
  } catch (error) {
    hideProgress();
    summarizeBtn.disabled = false;
    showStatus(error.message, 'error');
    addDebug('Summary Error', { error: error.message });
  }
});

// Save documents
saveBtn.addEventListener('click', async () => {
  saveBtn.disabled = true;
  showProgress('Saving documents...');

  try {
    const response = await fetch('/api/save-documents', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ documents: groupedDocuments }),
    });

    if (!response.ok) {
      const error = await response.json();
      throw new Error(error.details || error.error || 'Save failed');
    }

    const data = await response.json();

    hideProgress();
    saveBtn.disabled = false;
    showStatus(data.message);

    addDebug('Documents Saved', {
      documentCount: data.documentCount,
      message: data.message,
    });
  } catch (error) {
    hideProgress();
    saveBtn.disabled = false;
    showStatus(error.message, 'error');
    addDebug('Save Error', { error: error.message });
  }
});

// Version badge and release notes modal
const versionBadge = document.getElementById('versionBadge');
const releaseModal = document.getElementById('releaseModal');
const modalClose = document.getElementById('modalClose');
const releaseNotesContent = document.getElementById('releaseNotesContent');

function initVersionBadge() {
  versionBadge.textContent = `v${APP_VERSION}`;
}

function formatReleaseDate(isoDate) {
  const d = new Date(isoDate);
  return d.toLocaleDateString('en-US', {
    year: 'numeric',
    month: 'short',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
  });
}

function renderReleaseNotes() {
  releaseNotesContent.innerHTML = RELEASES.map(
    (release) => `
    <div class="release-entry">
      <div class="release-version">
        <span class="tag">v${release.version}</span>
        <span class="date">${formatReleaseDate(release.date)}</span>
      </div>
      <div class="release-title">${release.title}</div>
      <ul class="release-changes">
        ${release.changes.map((c) => `<li>${c}</li>`).join('')}
      </ul>
    </div>
  `
  ).join('');
}

versionBadge.addEventListener('click', () => {
  renderReleaseNotes();
  releaseModal.classList.add('visible');
});

modalClose.addEventListener('click', () => {
  releaseModal.classList.remove('visible');
});

releaseModal.addEventListener('click', (e) => {
  if (e.target === releaseModal) {
    releaseModal.classList.remove('visible');
  }
});

// Load releases from generated JSON and initialize
async function init() {
  initLegend();

  try {
    const res = await fetch('/releases.json');
    if (res.ok) {
      const data = await res.json();
      APP_VERSION = data.version;
      RELEASES = data.releases;
    }
  } catch {
    // releases.json not generated yet — badge will show "..."
  }

  initVersionBadge();
}

init();
